+		stage->properties().configureInitFrom(Stage::PARENT, { "group" });
+		stage->setGoal(arm_home_pose_);
+		stage->restrictDirection(stages::MoveTo::FORWARD);
+		t.add(std::move(stage));
+	}
+}
